  var s3 = new[] { 17, 19, 25 };
  var merged = s1.SortedMerge( OrderByDirection.Ascending, s2, s3 );
  var result = merged.ToArray();
  // result will be:
  // { 2, 3, 4, 7, 11, 17, 19, 20, 25 }

